firmware_template.source:
#include "bt_a2dp_speaker.h"
#include <BluetoothA2DPSink.h>

static BluetoothA2DPSink a2dp_sink;
static int volume = 100;

void bt_a2dp_setup(const char* bt_name) {
  i2s_pin_config_t pins = {
    .bck_io_num = 16,
    .ws_io_num = 15,
    .data_out_num = 17,
    .data_in_num = -1
  };
  a2dp_sink.set_pin_config(pins);
  a2dp_sink.start(bt_name);
  Serial.printf("[bt_a2dp] Ready: %s\n", bt_name);
}

void bt_a2dp_set_volume(int percent) {
  volume = percent;
  a2dp_sink.set_volume(percent * 127 / 100);
}

bool bt_a2dp_is_connected() {
  return a2dp_sink.is_connected();
}

bool bt_a2dp_is_playing() {
  return a2dp_sink.get_audio_state() == ESP_A2D_AUDIO_STATE_STARTED;
}
